/*
 * OpenCL kernel for streamcluster pgain computation
 * Translated from OpenMP source
 */

#define CACHE_LINE 512

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

/*
 * Kernel: pgain_kernel
 * Computes the gain of opening a new facility at point x
 * 
 * Arguments:
 * - p: Point data (weight, assign, cost)
 * - coord: Coordinate data (flattened: num * dim)
 * - work_mem: Working memory for accumulation (num * (K+1))
 * - center_table: Mapping from point index to center index
 * - switch_membership: Boolean flag for each point
 * - num: Number of points
 * - dim: Dimension of each point
 * - x: Index of candidate point to open
 * - K: Number of centers
 */

__kernel void pgain_kernel(
    __global const Point_Struct* p,
    __global const float* coord,
    __global float* work_mem,
    __global const int* center_table,
    __global char* switch_membership,
    __local float* local_coord,
    int num,
    int dim,
    long x,
    int K)
{
    int i = get_global_id(0);

    if (i >= num) return;

    // Load coordinates of point x into local memory
    // Each threadblock caches the coordinates of point x
    int tid = get_local_id(0);
    int stride = get_local_size(0);

    for (int d = tid; d < dim; d += stride) {
        local_coord[d] = coord[x * dim + d];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute distance from point i to point x
    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[i * dim + d] - local_coord[d];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    float current_cost = p[i].cost;

    if (x_cost < current_cost) {
        // Point i should switch to center x
        switch_membership[i] = 1;
        work_mem[i * (K + 1) + K] += (x_cost - current_cost);
    } else {
        // Accumulate savings for current center
        int assign = (int)p[i].assign;
        int center_idx = center_table[assign];
        if (center_idx >= 0 && center_idx < K) {
            work_mem[center_idx + i * (K + 1)] += (current_cost - x_cost);
        }
    }
}

/*
 * Kernel: init_centers_kernel
 * Initializes center table and counts centers
 */

__kernel void init_centers_kernel(
    __global const char* is_center,
    __global int* center_table,
    __global int* work_mem,
    int num,
    int stride,
    int pid)
{
    int i = get_global_id(0);

    if (i >= num) return;

    if (is_center[i]) {
        center_table[i] = 1;
    } else {
        center_table[i] = 0;
    }

    work_mem[pid * stride] += center_table[i];
}

/*
 * Kernel: compute_hiz_kernel
 * Computes initial hiz value for each thread
 */

__kernel void compute_hiz_kernel(
    __global const Point_Struct* p,
    __global const float* coord,
    __global float* hizs,
    int num,
    int dim,
    int pid,
    long k1,
    long k2)
{
    int idx = get_global_id(0);
    long kk = k1 + idx;

    if (kk >= k2) return;

    float myhiz = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[kk * dim + d] - coord[0 * dim + d];
        myhiz += diff * diff;
    }
    myhiz *= p[kk].weight;

    hizs[pid] += myhiz;
}

/*
 * Kernel: speedy_init_kernel
 * Initializes costs for speedy algorithm
 */

__kernel void speedy_init_kernel(
    __global Point_Struct* p,
    __global const float* coord,
    int num,
    int dim,
    long k1,
    long k2)
{
    int idx = get_global_id(0);
    long k = k1 + idx;

    if (k >= k2) return;

    float distance = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[k * dim + d] - coord[0 * dim + d];
        distance += diff * diff;
    }

    p[k].cost = distance * p[k].weight;
    p[k].assign = 0;
}

/*
 * Kernel: contcenters_kernel
 * Consolidates centers by computing weighted averages
 */

__kernel void contcenters_kernel(
    __global Point_Struct* p,
    __global float* coord,
    int num,
    int dim)
{
    int i = get_global_id(0);

    if (i >= num) return;

    long assign = p[i].assign;

    if (assign != i) {
        float relweight = p[assign].weight + p[i].weight;
        relweight = p[i].weight / relweight;

        for (int ii = 0; ii < dim; ii++) {
            coord[assign * dim + ii] *= (1.0f - relweight);
            coord[assign * dim + ii] += coord[i * dim + ii] * relweight;
        }
        p[assign].weight += p[i].weight;
    }
}

/*
 * Kernel: update_assign_kernel
 * Updates point assignments after pgain computation
 */

__kernel void update_assign_kernel(
    __global Point_Struct* p,
    __global const float* coord,
    __global const char* switch_membership,
    __global const float* gl_lower,
    __global const int* center_table,
    __global char* is_center,
    int num,
    int dim,
    long x,
    int K)
{
    int i = get_global_id(0);

    if (i >= num) return;

    long assign = p[i].assign;
    int center_idx = center_table[assign];

    bool close_center = (center_idx >= 0 && center_idx < K && gl_lower[center_idx] > 0);

    if (switch_membership[i] == 1 || close_center) {
        float new_cost = 0.0f;
        for (int d = 0; d < dim; d++) {
            float diff = coord[i * dim + d] - coord[x * dim + d];
            new_cost += diff * diff;
        }
        p[i].cost = new_cost * p[i].weight;
        p[i].assign = x;
    }

    if (is_center[i] && center_idx >= 0 && center_idx < K && gl_lower[center_idx] > 0) {
        is_center[i] = 0;
    }

    if (i == x) {
        is_center[i] = 1;
    }
}
